svg.script:
const svg = document.getElementById("cloudling");
const eyes = document.getElementById("eyes-js");
const body = document.getElementById("breath-js");
const eyeGrad = document.getElementById("eye-grad");
const eyeL = document.getElementById("eye-l");
const eyeR = document.getElementById("eye-r");
const readout = document.getElementById("offset-readout");
const scaleReadout = document.getElementById("scale-readout");

const face = { x: 9.95, y: 11.975 };
const EYE_BASE = {
  l: { x: 6.65, y: 9.65, h: 4.65, rx: 1.1 },
  r: { x: 11.05, y: 9.65, h: 4.65, rx: 1.1 },
};
const params = {
  eyeMax: 2.05,
  yClamp: 0.85,
  maxRotDeg: 13,
  cloudLag: 0.20,
  scaleLow: 0.96,
  breathPeriod: 5.0,
  distNear: 6,
  distFar: 20,
  distMaxScale: 1.15,
  distRecenter: 0.5,
  flowPeriod: 5.5,
  flowAmp: 4,
  blinkInterval: 6.0,
  blinkDur: 0.16,
  eyeTrack: 0.06,
  recenter: 0.15,
};
let pointerInside = false;
let pointer = { ...face };
let current = { x: 0, y: 0 };
let target = { x: 0, y: 0 };
let cloudRotate = 0;
let currentDistScale = 1.0;
let lastT = performance.now();
const startT = performance.now();
let nextBlinkT = 3 + Math.random() * 2;
let blinkActive = false;
let blinkStartT = 0;

function clamp(v, min, max) {
  return Math.max(min, Math.min(max, v));
}

function svgPointFromEvent(e) {
  const r = svg.getBoundingClientRect();
  return {
    x: (e.clientX - r.left) * (48 / r.width) - 12,
    y: (e.clientY - r.top) * (48 / r.height) - 12,
  };
}

function updateTarget() {
  if (!pointerInside) {
    target.x = 0;
    target.y = 0;
    return;
  }
  const dx = pointer.x - face.x;
  const dy = pointer.y - face.y;
  const dist = Math.hypot(dx, dy);
  if (dist < 0.01) {
    target.x = 0;
    target.y = 0;
    return;
  }
  const sat = Math.tanh(dist / 6);
  target.x = (dx / dist) * sat * params.eyeMax;
  target.y = clamp((dy / dist) * sat * params.eyeMax, -params.eyeMax * params.yClamp, params.eyeMax * params.yClamp);
}

function tick(now) {
  const dt = Math.min(0.05, (now - lastT) / 1000);
  lastT = now;
  const t = (now - startT) / 1000;
  updateTarget();
  const eyeTime = pointerInside ? params.eyeTrack : params.recenter;
  const eyeRate = 1 - Math.exp(-dt / eyeTime);
  current.x += (target.x - current.x) * eyeRate;
  current.y += (target.y - current.y) * eyeRate;

  const maxRot = params.maxRotDeg * Math.PI / 180;
  const targetRot = (current.x / Math.max(params.eyeMax, 0.01)) * maxRot;
  cloudRotate += (targetRot - cloudRotate) * params.cloudLag;

  const phase = (Math.cos(2 * Math.PI * t / params.breathPeriod) + 1) / 2;
  const breathScale = params.scaleLow + (1 - params.scaleLow) * phase;
  let targetDistScale = 1.0;
  if (pointerInside) {
    const dx = pointer.x - face.x;
    const dy = pointer.y - face.y;
    const dist = Math.hypot(dx, dy);
    if (dist > params.distNear) {
      const t01 = Math.min((dist - params.distNear) / Math.max(params.distFar - params.distNear, 0.01), 1);
      targetDistScale = 1.0 + (params.distMaxScale - 1.0) * t01;
    }
  }
  const distRate = 1 - Math.exp(-dt / params.distRecenter);
  currentDistScale += (targetDistScale - currentDistScale) * distRate;
  const finalScale = breathScale * currentDistScale;
  const angleDeg = cloudRotate * 180 / Math.PI;
  body.setAttribute(
    "transform",
    `translate(12 12) rotate(${angleDeg.toFixed(3)}) scale(${finalScale.toFixed(4)}) translate(-12 -12)`
  );
  const eyeScale = currentDistScale;
  eyes.setAttribute(
    "transform",
    `translate(${current.x.toFixed(3)} ${current.y.toFixed(3)}) translate(${face.x} ${face.y}) scale(${eyeScale.toFixed(4)}) translate(${-face.x} ${-face.y})`
  );
  applyBlink(t);
  const flowOffset = Math.sin(2 * Math.PI * t / params.flowPeriod) * params.flowAmp;
  eyeGrad.setAttribute("y1", (3 + flowOffset).toFixed(2));
  eyeGrad.setAttribute("y2", (21 + flowOffset).toFixed(2));
  readout.textContent = `offset: ${current.x.toFixed(2)}, ${current.y.toFixed(2)}`;
  scaleReadout.textContent = `scale: ${finalScale.toFixed(3)}, rot: ${angleDeg.toFixed(1)}deg`;
  requestAnimationFrame(tick);
}

function getBlinkScale(t) {
  if (!blinkActive && t > nextBlinkT) {
    blinkActive = true;
    blinkStartT = t;
  }
  if (blinkActive) {
    const d = t - blinkStartT;
    const half = params.blinkDur / 2;
    if (d < half) return 1 - 0.94 * (d / half);
    if (d < params.blinkDur) return 0.06 + 0.94 * ((d - half) / half);
    blinkActive = false;
    nextBlinkT = t + params.blinkInterval * (0.8 + Math.random() * 0.4);
  }
  return 1;
}

function setBlinkRect(rect, base, scale) {
  const h = Math.max(base.h * scale, 0.15);
  const y = base.y + (base.h - h) / 2;
  const rx = Math.min(base.rx, h / 2);
  rect.setAttribute("height", h.toFixed(3));
  rect.setAttribute("y", y.toFixed(3));
  rect.setAttribute("rx", rx.toFixed(3));
  rect.setAttribute("ry", rx.toFixed(3));
}

function applyBlink(t) {
  const scale = getBlinkScale(t);
  setBlinkRect(eyeL, EYE_BASE.l, scale);
  setBlinkRect(eyeR, EYE_BASE.r, scale);
}

window.addEventListener("pointermove", e => {
  const r = svg.getBoundingClientRect();
  const inside = e.clientX >= r.left && e.clientX <= r.right
    && e.clientY >= r.top && e.clientY <= r.bottom;
  pointerInside = inside;
  if (inside) pointer = svgPointFromEvent(e);
});
svg.addEventListener("pointerleave", () => {
  pointerInside = false;
});
window.__cloudlingSetPointer = payload => {
  if (!payload || !Number.isFinite(payload.x) || !Number.isFinite(payload.y)) return;
  pointer.x = payload.x;
  pointer.y = payload.y;
  pointerInside = !!payload.inside;
};
requestAnimationFrame(tick);
